// src/components/LoginScreen.jsx
const LoginScreen = ({ onLogin }) => {
  return (
    <div style={{
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      height: '100vh',
      background: '#f9fafb',
      fontFamily: 'sans-serif'
    }}>
      <div style={{
        textAlign: 'center',
        padding: '32px',
        borderRadius: '12px',
        background: 'white',
        boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
        maxWidth: '400px',
        width: '90%'
      }}>
        <h2>OzonInsight</h2>
        <p>Подключите аккаунт для анализа</p>
        <button
          onClick={onLogin}
          style={{
            padding: '12px 24px',
            background: '#0ea5e9',
            color: 'white',
            border: 'none',
            borderRadius: '8px',
            cursor: 'pointer',
            fontSize: '16px',
            width: '100%'
          }}
        >
          Войти через Ozon
        </button>
      </div>
    </div>
  );
};

export default LoginScreen;
